import CartContext from './CartContext'
import React,{useState} from 'react'

function CartState(props) {
    const host = "http://localhost:5000"
    const cartinitial = []
    const [carts, setcarts] = useState(cartinitial)


    //add tp cart
    const addtocart = async (id,image,title) => {
        const response = await fetch(`${host}/api/auth/addToCart?productId=${id}`, {
            method: "POST",
            headers: {
                'Content-Type': 'application/json',
                'auth-token': localStorage.getItem('token')
            },
            body: JSON.stringify({id,image,title}),
        });

        const cart = await response.json()
        setcarts(carts.concat(cart));
    };
    return (
        <CartContext.Provider value={{carts,setcarts,addtocart} }>
            {props.children};
        </CartContext.Provider>
    )
}

export default CartState
